import requests
import json

# --- Configuration ---
KONG_ADMIN_URL = "http://localhost:8001"  # Replace with your Kong Admin API URL

# --- Services to Create ---
services_config = [
    {
        "name": "my-service-a",
        "url": "http://mockbin.org/status/200",
        "tags": ["automation", "test"],
        "retries": 5
    },
    {
        "name": "my-service-b",
        "url": "http://httpbin.org/get",
        "tags": ["automation", "test"],
        "connect_timeout": 60000
    }
]

# --- Routes to Create (associated with services by name) ---
routes_config = [
    {
        "name": "my-route-a-path",
        "paths": ["/api/a"],
        "protocols": ["http", "https"],
        "strip_path": True,
        "service_name": "my-service-a"  # Link to service by name
    },
    {
        "name": "my-route-a-host",
        "hosts": ["a.example.com"],
        "protocols": ["http", "https"],
        "service_name": "my-service-a"
    },
    {
        "name": "my-route-b",
        "paths": ["/api/b"],
        "protocols": ["http", "https"],
        "strip_path": True,
        "service_name": "my-service-b"
    }
]

# --- Upstreams and Targets to Create ---
upstreams_config = [
    {
        "name": "my-upstream-a",
        "slots": 10,
        "healthchecks": {
            "active": {
                "http_path": "/",
                "timeout": 1,
                "interval": 5,
                "unhealthy": {
                    "http_failures": 2,
                    "timeouts": 2
                }
            },
            "passive": {
                "unhealthy": {
                    "http_failures": 5,
                    "timeouts": 5
                }
            }
        },
        "targets": [
            {"target": "192.168.1.100:8080", "weight": 100},
            {"target": "192.168.1.101:8080", "weight": 50}
        ]
    }
]

# --- Helper function to make API calls ---
def make_kong_request(method, endpoint, data=None):
    url = f"{KONG_ADMIN_URL}{endpoint}"
    headers = {"Content-Type": "application/json"}
    try:
        if method.upper() == "POST":
            response = requests.post(url, headers=headers, data=json.dumps(data))
        elif method.upper() == "GET":
            response = requests.get(url, headers=headers)
        elif method.upper() == "DELETE":
            response = requests.delete(url, headers=headers)
        else:
            raise ValueError(f"Unsupported HTTP method: {method}")

        response.raise_for_status()  # Raise an exception for HTTP errors (4xx or 5xx)
        return response.json()
    except requests.exceptions.RequestException as e:
        print(f"Error {method}ing {endpoint}: {e}")
        if hasattr(e, 'response') and e.response is not None:
            print(f"Response status: {e.response.status_code}")
            print(f"Response body: {e.response.text}")
        return None

# --- Main Configuration Logic ---
def configure_kong():
    print(f"Connecting to Kong Admin API at: {KONG_ADMIN_URL}")

    # 1. Create Services
    print("\n--- Creating Services ---")
    created_services = {}
    for service_data in services_config:
        service_name = service_data["name"]
        print(f"Creating service: {service_name}...")
        response = make_kong_request("POST", "/services", service_data)
        if response:
            print(f"Service '{service_name}' created successfully. ID: {response['id']}")
            created_services[service_name] = response
        else:
            print(f"Failed to create service '{service_name}'.")

    # 2. Create Routes
    print("\n--- Creating Routes ---")
    for route_data in routes_config:
        route_name = route_data["name"]
        service_name_to_link = route_data.pop("service_name", None)

        if not service_name_to_link:
            print(f"Skipping route '{route_name}': No 'service_name' specified to link to.")
            continue

        if service_name_to_link not in created_services:
            print(f"Skipping route '{route_name}': Service '{service_name_to_link}' not found or failed to create.")
            continue

        # Link route to the created service by its ID
        route_data["service"] = {"id": created_services[service_name_to_link]["id"]}

        print(f"Creating route: {route_name} for service '{service_name_to_link}'...")
        response = make_kong_request("POST", "/routes", route_data)
        if response:
            print(f"Route '{route_name}' created successfully. ID: {response['id']}")
        else:
            print(f"Failed to create route '{route_name}'.")

    # 3. Create Upstreams and Targets
    print("\n--- Creating Upstreams and Targets ---")
    for upstream_data in upstreams_config:
        upstream_name = upstream_data["name"]
        targets_to_create = upstream_data.pop("targets", [])

        print(f"Creating upstream: {upstream_name}...")
        response = make_kong_request("POST", "/upstreams", upstream_data)
        if response:
            print(f"Upstream '{upstream_name}' created successfully. ID: {response['id']}")
            upstream_id = response['id']

            # Create targets for this upstream
            for target_data in targets_to_create:
                print(f"  Adding target '{target_data['target']}' to upstream '{upstream_name}'...")
                target_response = make_kong_request("POST", f"/upstreams/{upstream_id}/targets", target_data)
                if target_response:
                    print(f"  Target '{target_data['target']}' added successfully. ID: {target_response['id']}")
                else:
                    print(f"  Failed to add target '{target_data['target']}' to upstream '{upstream_name}'.")
        else:
            print(f"Failed to create upstream '{upstream_name}'.")

    print("\n--- Kong Configuration Script Finished ---")

if __name__ == "__main__":
    configure_kong()